// =========================================================
// Normaliza resposta da API → formato do RPC fn_supest_ingest_snapshots
//   - adiciona snapshot_date=HOJE
//   - todos os campos viram string; RPC parseia PT-BR
//   - quebra em lotes de 1000 para reduzir tamanho do payload
// =========================================================
const respostas = items.map(i => i.json).flat();
// API pode devolver array direto OU {data:[...]}
let rows = [];
for (const r of respostas) {
  if (Array.isArray(r)) rows = rows.concat(r);
  else if (Array.isArray(r.data)) rows = rows.concat(r.data);
  else rows.push(r);
}

const hoje = new Date();
const snapshot_date = hoje.toISOString().slice(0,10);

function s(v) { return v == null ? null : String(v); }

const KEYS_PASSTHRU = [
  'filial','setor','departamento','secao','fornecedor',
  'grade','estoque','preco','quant_vendas','media_dia','quant_movimentos',
  'dias_venda','maximo','ultima_entrada','ultima_saida','mix','multiplo','giro'
];

const normalized = rows.map(r => {
  const o = { snapshot_date };
  o.codigo_produto    = s(r.codigo);
  o.descricao_produto = s(r.descricao);
  o.cod_barras        = s(r.cod_barras);
  for (const k of KEYS_PASSTHRU) o[k] = s(r[k]);
  return o;
});

const CHUNK = 1000;
const lotes = [];
for (let i = 0; i < normalized.length; i += CHUNK) {
  lotes.push({
    json: {
      snapshot_date,
      lote: Math.floor(i / CHUNK) + 1,
      total_lotes: Math.ceil(normalized.length / CHUNK),
      total_linhas: normalized.length,
      rows: normalized.slice(i, i + CHUNK),
    }
  });
}
return lotes;

// Diretor + supervisor — recebem o resumo de TODAS as filiais
return items
  .map(it => ({
    json: {
      email_login: (it.json.id || it.json.email_login || '').toLowerCase(),
      nome:        it.json.nome,
      funcao:      it.json.funcao,
      agentes:     it.json.agentes,
      whatsapp:    String(it.json.whatsapp || '').trim(),
      loja:        it.json.loja,
    }
  }))
  .filter(it => {
    const d = it.json;
    return ['diretor','supervisor','ti'].includes(d.funcao)
      && Array.isArray(d.agentes) && d.agentes.includes('supervisor_estoque')
      && d.whatsapp && d.whatsapp !== '0' && d.whatsapp.length > 5
      && d.email_login;
  });

// Resolve visibilidade (igual ao padrão dos outros agentes):
//   - loja='todas' → ver todas as filiais
//   - array de strings → filtra por essas filiais
const usuarios   = $('Filtrar diretor/supervisor').all().map(it => it.json);
const resumoTodo = $('View: resumo por filial (dir)').all().map(it => it.json);
const SENTINEL = 'todas';
function extraiCod(raw) {
  if (raw == null) return null;
  const s = String(raw).trim();
  if (!s) return null;
  const m = s.match(/^(\d+)/);
  return m ? m[1] : s.toLowerCase();
}
function resolveLojas(lojaRaw) {
  if (typeof lojaRaw === 'string' && lojaRaw.trim().toLowerCase() === SENTINEL) return { wildcard: true, filiais: [] };
  const arr = Array.isArray(lojaRaw) ? lojaRaw : (lojaRaw == null || lojaRaw === '' ? [] : [lojaRaw]);
  if (arr.some(x => String(x).trim().toLowerCase() === SENTINEL)) return { wildcard: true, filiais: [] };
  const filiais = arr.map(extraiCod).filter(Boolean).filter((v,i,a)=>a.indexOf(v)===i);
  return { wildcard: false, filiais };
}
return usuarios.map(u => {
  const { wildcard, filiais } = resolveLojas(u.loja);
  const resumo = wildcard ? resumoTodo : resumoTodo.filter(r => filiais.includes(String(r.filial_cod)));
  return { json: { email_login: u.email_login, nome: u.nome, whatsapp: u.whatsapp, funcao: u.funcao, wildcard, filiais, resumo } };
});

// Mensagem para diretor/supervisor
const u = $input.first().json;
function num(v) { return v == null ? '—' : Number(v).toLocaleString('pt-BR', { maximumFractionDigits: 0 }); }
const filiais = (u.resumo || []).filter(r => Number(r.alertas_pendentes||0) > 0)
                  .sort((a,b) => Number(b.alertas_pendentes) - Number(a.alertas_pendentes));
const totalAlertas  = filiais.reduce((s,r)=> s + Number(r.alertas_pendentes||0), 0);
const totalProdutos = filiais.reduce((s,r)=> s + Number(r.produtos_afetados||0), 0);
const linhas = filiais.map(r => {
  const desc = r.filial_desc ? r.filial_desc.replace(/^\d+\s*-\s*/, '') : '';
  return `   • *${r.filial_cod}*${desc?' '+desc:''} — ${num(r.alertas_pendentes)} alerta(s)`
    + ` (queda:${num(r.alertas_queda)} | aumento:${num(r.alertas_aumento)})`;
}).join('\n');
const message = `Olá, *${u.nome}*!\n\n*Supervisor de Estoque* — variações relevantes hoje (vs média 7d, ≥20%):\n\nTotal: *${num(totalAlertas)}* alerta(s) em ${filiais.length} filial(is) · ${num(totalProdutos)} produto(s) afetado(s).\n\nQuebra por filial:\n${linhas}`;
return [{ json: { phone: u.whatsapp, message, email_login: u.email_login } }];

// Gerente — recebe APENAS sua(s) filial(is)
return items
  .map(it => ({
    json: {
      email_login: (it.json.id || it.json.email_login || '').toLowerCase(),
      nome:        it.json.nome,
      funcao:      it.json.funcao,
      agentes:     it.json.agentes,
      whatsapp:    String(it.json.whatsapp || '').trim(),
      loja:        it.json.loja,
    }
  }))
  .filter(it => {
    const d = it.json;
    return d.funcao === 'gerente'
      && Array.isArray(d.agentes) && d.agentes.includes('supervisor_estoque')
      && d.whatsapp && d.whatsapp !== '0' && d.whatsapp.length > 5
      && d.email_login;
  });

const gerentes   = $('Filtrar gerentes').all().map(it => it.json);
const resumoTodo = $('View: resumo por filial (ger)').all().map(it => it.json);
const SENTINEL = 'todas';
