  const arr = Array.isArray(lojaRaw) ? lojaRaw : (lojaRaw == null || lojaRaw === '' ? [] : [lojaRaw]);
  if (arr.some(x => String(x).trim().toLowerCase() === SENTINEL)) return { wildcard: true, filiais: [] };
  const filiais = arr.map(extraiCod).filter(Boolean).filter((v,i,a)=>a.indexOf(v)===i);
  return { wildcard: false, filiais };
}
return gerentes.map(u => {
  const { wildcard, filiais } = resolveLojas(u.loja);
  const resumo = wildcard ? resumoTodo : resumoTodo.filter(r => filiais.includes(String(r.filial_cod)));
  return { json: { email_login: u.email_login, nome: u.nome, whatsapp: u.whatsapp, wildcard, filiais, resumo } };
});

const u = $input.first().json;
function num(v) { return v == null ? '—' : Number(v).toLocaleString('pt-BR', { maximumFractionDigits: 0 }); }
const filiais = (u.resumo || []).filter(r => Number(r.alertas_pendentes||0) > 0)
                  .sort((a,b)=>Number(b.alertas_pendentes)-Number(a.alertas_pendentes));
const total = filiais.reduce((s,r)=>s+Number(r.alertas_pendentes||0),0);
const blocos = filiais.map(r => {
  return `*${r.filial_desc || r.filial_cod}*
   • Total de alertas: ${num(r.alertas_pendentes)} (queda:${num(r.alertas_queda)} | aumento:${num(r.alertas_aumento)})
   • Por métrica — media_dia:${num(r.alertas_media_dia)} · dias_venda:${num(r.alertas_dias_venda)} · giro:${num(r.alertas_giro)}
   • Produtos afetados: ${num(r.produtos_afetados)} em ${num(r.secoes_afetadas)} seção(ões)`;
}).join('

');
const link = $env.APP_URL_SUPEST || 'http://app.interno/agente/supervisor_estoque';
const plural = filiais.length === 1 ? 'sua loja' : 'suas lojas';
const message = `Olá, *${u.nome}*!

*Supervisor de Estoque* — variações em ${plural} (vs média 7d, ≥20%):

Total: *${num(total)}* alerta(s).

${blocos}

Acesse: ${link}`;
return [{ json: { phone: u.whatsapp, message, email_login: u.email_login } }];

// Comprador — recebe APENAS suas seções (já está atribuído por chave_secao)
return items
  .map(it => ({
    json: {
      email_login: (it.json.id || it.json.email_login || '').toLowerCase(),
      nome:        it.json.nome,
      funcao:      it.json.funcao,
      agentes:     it.json.agentes,
      whatsapp:    String(it.json.whatsapp || '').trim(),
    }
  }))
  .filter(it => {
    const d = it.json;
    return d.funcao === 'comprador'
      && Array.isArray(d.agentes) && d.agentes.includes('supervisor_estoque')
      && d.whatsapp && d.whatsapp !== '0' && d.whatsapp.length > 5
      && d.email_login;
  });

const compradores = $('Filtrar compradores').all().map(it => it.json);
const resumoResp  = $('View: resumo por responsável').all().map(it => it.json);
const drill       = $('View: drill filial × comprador').all().map(it => it.json);
function matchByEmail(arr, email) {
  if (!email) return null;
  return arr.find(r => String(r.usuario_email_login || '').toLowerCase() === email) || null;
}
return compradores.map(c => {
  const resumo = matchByEmail(resumoResp, c.email_login);
  const porFilial = resumo
    ? drill.filter(d => String(d.usuario_id) === String(resumo.usuario_id))
           .filter(d => Number(d.alertas_pendentes || 0) > 0)
           .sort((a,b)=>Number(b.alertas_pendentes)-Number(a.alertas_pendentes))
    : [];
  return {
    json: {
      email_login: c.email_login,
      nome:        c.nome,
      whatsapp:    c.whatsapp,
      alertas_pendentes: Number(resumo?.alertas_pendentes || 0),
      filiais_afetadas:   Number(resumo?.filiais_afetadas || 0),
      secoes_afetadas:    Number(resumo?.secoes_afetadas || 0),
      alertas_media_dia:  Number(resumo?.alertas_media_dia || 0),
      alertas_dias_venda: Number(resumo?.alertas_dias_venda || 0),
      alertas_giro:       Number(resumo?.alertas_giro || 0),
      por_filial: porFilial,
    }
  };
});

const u = $input.first().json;
function num(v) { return v == null ? '—' : Number(v).toLocaleString('pt-BR', { maximumFractionDigits: 0 }); }
const porFilial = (u.por_filial || []).slice(0, 5);
const linhasFiliais = porFilial.length
  ? porFilial.map(f => `   • *${f.filial_cod}* — ${num(f.alertas_pendentes)} alerta(s)`).join('\n')
  : '';
const extras = (u.por_filial || []).length > porFilial.length
  ? `\n   …e mais ${u.por_filial.length - porFilial.length} filial(is).`
  : '';
const metricas = `media_dia:${num(u.alertas_media_dia)} · dias_venda:${num(u.alertas_dias_venda)} · giro:${num(u.alertas_giro)}`;
const message = `Olá, *${u.nome}*!\n\n*Supervisor de Estoque* — variações nas suas seções (vs média 7d, ≥20%):\n\nVocê tem *${num(u.alertas_pendentes)}* alerta(s) em ${num(u.filiais_afetadas)} filial(is) · ${num(u.secoes_afetadas)} seção(ões).\nDistribuição: ${metricas}\n${porFilial.length ? '\nPrincipais filiais:\n' + linhasFiliais + extras : ''}`;
return [{ json: { phone: u.whatsapp, message, email_login: u.email_login } }];
